@module swingEditor  src=swingEditor.lua  loc=747  sha=7ef043d  mode=chunk  self=swingEditor
@deps cm, ds, chrome, ctx, gui, facade, modalHost, lib

# Invariants & contracts
  @invariant  editor stores no swing data; swingRead = tier copy of state.name, else merged floor  @ 4
  @invariant  all writes go through swingWrite (idempotent); commit() triggers cross-take reswing  @ 5
  @invariant  state == nil iff closed; open(name?) re-selects when open; close() is page-driven  @ 6
  @invariant  snapshot captured at open() and palette-switch; never mutated; Reset writes a deepClone  @ 7
  @invariant  shift is in QN and atom-independent — preserved across atom swap, only re-clamped to the new atom's cap  @ 8
  @invariant  on period change shift scales by newPeriod/oldPeriod, holding resolved s = shift/tileQN (and thus slope) constant; then re-clamped  @ 9
  @invariant  slider lo/hi = T_tile · {-negRange, +posRange} (asymmetric for shuffle/tilt); Wild unlocks hard, otherwise clamped to ±SWING_SOFT_QN; hi <= 0 freezes the slider  @ 10
  @invariant  atom-combo speaks tile-QN (user-period × pulsesPerCycle); writes divide back via periodOverPPC so storage stays user-period  @ 11

# Shapes
  @shape  state = { name, tier, snapshot, rpb, wild }  -- composite is NOT cached here  @ 12
  @shape  PeriodPreset = { label = string, period = number|{num,den} }  -- period in user-facing QN  @ 13

